  ('police-94737317-moex-00059', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋，有關法官迴避制度，下列敘述何者錯誤？', '["法官迴避制度屬訴訟權保障之核心內容", "智慧財產法院之技術審查官亦有迴避制度之適用", "審理相牽涉民事與行政訴訟事件之法官間，是否有迴避制度之適用，屬立法裁量之範圍", "辦理智慧財產刑事訴訟之法官，得參與就該訴訟事件相牽涉之智慧財產行政訴訟之審判，無須迴避，違 反憲法公平審判之要求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00060', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '司法院釋字第779號解釋認為，原土地稅法第39條第2項僅就依都市計畫法指定之公共設施保留地，免 徵其土地增值稅；至非都市土地經編定為交通用地，且依法核定為公共設施用地者，則不予免徵土地增值 稅之規定違憲，係違反下列何者？', '["租稅法定原則", "實質課稅原則", "平等權", "比例原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00061', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '憲法本文有關國民經濟之規定，下列敘述何者錯誤？', '["公用事業以公營為原則", "合作事業應受國家之獎勵", "公私營事業如有妨害國計民生平衡發展，國家得以法律限制之", "國民生產事業應受國家之獎勵、指導及保護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00062', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋意旨，有關人身自由，下列敘述何者錯誤？', '["依傳染病防治法所為之強制集中隔離措施，屬於憲法第8條第1項所稱之拘禁。故主管機關於提審法 修正施行後，均需告知相對人其有聲請提審之權利", "傳染病防治法之強制隔離措施，性質上屬於拘禁措施，應由法院加以決定，主管機關不得單獨、逕行決 定之，必待聲請法院同意後為之", "違警罰法所規定之拘留及罰役，以及刑事訴訟法原本賦予檢察官之羈押權，性質上均屬拘禁措施，均牴 觸憲法第8條規定", "少年事件處理法之收容及感化教育，以及社會秩序維護法所規定之拘留，性質上均屬拘禁措施，故均應 由法院決定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00063', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '關於司法院釋字第744號解釋，下列敘述何者錯誤？', '["廣告之事前審查乃對言論自由之重大干預，原則上應為違憲", "商業言論皆受憲法第11條言論自由之同等保障", "廣告具商業上意見表達之性質", "化妝品廣告的事前審查須以嚴格標準審查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00064', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院釋字第756號解釋意旨，下列敘述何者錯誤？', '["書信之內容涉及通訊內容之秘密性，屬憲法保障秘密通訊自由之核心內涵", "監獄管理人員開拆受刑人信件包裹，檢查內容物之外觀，並不當然影響通訊之秘密性", "監獄管理人員閱讀受刑人書信內容，對秘密通訊自由之侵害程度，與書信種類或通訊對象無關", "依通訊雙方之身分不同，其秘密通訊自由受憲法保障之程度可能不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00065', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '有關結社自由，下列敘述何者錯誤？', '["保障人民得以團體之形式發展個人人格", "促使具公民意識之公民組成團體參與經濟、社會及政治事務", "保障範圍不包括成立非法人團體", "團體之形成、存續、命名等屬結社自由之保障範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL)
